<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">max_completion_tokens</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#FAB387;"> 4096</span><span style="color:#9399B2;">,</span></span>
